void solveCase(int n, int x, int *a) {

    int *bit_locs[31];
    int sizes[31] = {0};
    int ptr[31] = {0};

    // allocate memory
    for (int i = 0; i < 31; i++)
        bit_locs[i] = (int*)malloc(n * sizeof(int));

    // precompute bit locations
    for (int i = 0; i < n; i++) {
        int v = a[i];
        for (int j = 30; j >= 0; j--) {
            if (v & (1 << j)) {
                bit_locs[j][sizes[j]++] = i;
            }
        }
    }

    int operations = 0;

    for (int i = 0; i < n - 1; i++) {
        if (operations == x) break;

        for (int j = 30; j >= 0; j--) {
            if (operations == x) break;

            if (a[i] & (1 << j)) {
                if (ptr[j] + 1 < sizes[j]) {
                    a[i] ^= (1 << j);
                    a[bit_locs[j][ptr[j] + 1]] ^= (1 << j);
                    ptr[j] += 2;
                } else {
                    a[i] ^= (1 << j);
                    a[n - 1] ^= (1 << j);
                }
                operations++;
            }
        }
    }

    int y = x - operations;

    // special case for n = 2
    if (n == 2 && (y % 2 == 1)) {
        a[0] ^= 1;
        a[1] ^= 1;
    }

    // free memory
    for (int i = 0; i < 31; i++)
        free(bit_locs[i]);
}

