class Solution {

    public int[] solveCase(int n, int x, int[] a) {

        ArrayList<Integer>[] bit_locs = new ArrayList[31];
        for (int i = 0; i < 31; i++) bit_locs[i] = new ArrayList<>();

        int[] ptr = new int[31];

        // Precompute bit locations
        for (int i = 0; i < n; i++) {
            int v = a[i];
            for (int j = 30; j >= 0; j--) {
                if ((v & (1 << j)) != 0)
                    bit_locs[j].add(i);
            }
        }

        int operations = 0;

        for (int i = 0; i < n - 1; i++) {
            if (operations == x) break;

            for (int j = 30; j >= 0; j--) {
                if (operations == x) break;

                if ((a[i] & (1 << j)) != 0) {

                    if (ptr[j] + 1 < bit_locs[j].size()) {
                        // Flip with next index having same set bit
                        a[i] ^= (1 << j);
                        a[bit_locs[j].get(ptr[j] + 1)] ^= (1 << j);
                        ptr[j] += 2;
                    } else {
                        // Use last element
                        a[i] ^= (1 << j);
                        a[n - 1] ^= (1 << j);
                    }

                    operations++;
                }
            }
        }

        int y = x - operations;

        // Special case for n = 2
        if (n == 2 && (y % 2 == 1)) {
            a[0] ^= 1;
            a[1] ^= 1;
        }

        return a;
    }
}

