class Solution {
    solveCase(n, x, a) {
        // bit_locs[j] = list of indices where j-th bit is set
        const bit_locs = Array.from({ length: 31 }, () => []);
        const ptr = Array(31).fill(0);

        // Precompute positions of each bit
        for (let i = 0; i < n; i++) {
            let v = a[i];
            for (let j = 30; j >= 0; j--) {
                if (v & (1 << j)) bit_locs[j].push(i);
            }
        }

        let operations = 0;

        for (let i = 0; i < n - 1; i++) {
            if (operations === x) break;

            for (let j = 30; j >= 0; j--) {
                if (operations === x) break;

                if (a[i] & (1 << j)) {
                    if (ptr[j] + 1 < bit_locs[j].length) {
                        // flip with next matching bit index
                        a[i] ^= (1 << j);
                        a[bit_locs[j][ptr[j] + 1]] ^= (1 << j);
                        ptr[j] += 2;
                    } else {
                        // flip with last element
                        a[i] ^= (1 << j);
                        a[n - 1] ^= (1 << j);
                    }
                    operations++;
                }
            }
        }

        let remaining = x - operations;

        // Special rule when n = 2
        if (n === 2 && (remaining % 2 === 1)) {
            a[0] ^= 1;
            a[1] ^= 1;
        }

        return a;
    }
}
